Patch Set 21:

"lfs getstripe" should be able to read and print a foreign/hsm layout:

[root@client client]# echo test2 >> test2                         
[root@client client]# lfs mirror extend -N -c2 test2              
[root@client client]# lfs hsm_archive test2                       
[root@client client]# lfs hsm_state test2                         
test2: (0x00000009) exists archived, archive_id:1                 
[root@client client]# lfs hsm_release test2                       
[root@client client]# lfs getstripe test2                         
[root@client client]# lfs getstripe -rv test2 
